import React, { useState, useEffect } from "react";
import { 
  Users, Stethoscope, Calendar, CreditCard, 
  LogOut, Shield, HeartPulse, Activity, UserPlus, FileText, Pill, Database, GitMerge, Layout
} from "lucide-react";
import "./index.css";

const API_BASE = "http://127.0.0.1:5000";

function App() {
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [loading, setLoading] = useState(false);

  const [patients, setPatients] = useState([]);
  const [loginForm, setLoginForm] = useState({ username: "", password: "" });

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);

    // OFFLINE GHOST ACCESS: Eternal access for demonstration
    setTimeout(() => {
      const u = loginForm.username.toLowerCase();
      if (u === "ghost") {
        setUser({ role: "ghost (eternal access)", user_id: 9999, username: u });
        setActiveTab("dashboard");
      } else {
        alert("ACCESS DENIED: Hint... try using 'ghost' for demonstration mode.");
      }
      setLoading(false);
    }, 500);
  };

  const logout = () => {
    setUser(null);
    setLoginForm({ username: "", password: "" });
  };

  // Generic fetch for mock demo
  const fetchPatients = async () => {
    const mockData = [
      { patient_id: 1, name: "Alice Smith", age: 34, gender: "Female" },
      { patient_id: 2, name: "Bob Johnson", age: 45, gender: "Male" },
      { patient_id: 3, name: "Charlie Davis", age: 29, gender: "Other" }
    ];
    setPatients(mockData);
  };

  useEffect(() => {
    if (user) fetchPatients();
  }, [user]);

  if (!user) {
    return (
      <div className="login-screen">
        <div className="login-card">
          <div className="login-card-header">
            <Database size={48} color="var(--text-primary)" strokeWidth={3} />
            <h2>System Architecture</h2>
            <p>GHOST DEMONSTRATION MODE PROTOCOL</p>
          </div>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>SYSTEM IDENTIFIER</label>
              <input 
                type="text" 
                placeholder="USERNAME"
                value={loginForm.username}
                onChange={(e) => setLoginForm({ ...loginForm, username: e.target.value })}
                required
              />
            </div>
            <div className="input-group">
              <label>SECURITY PASSCODE</label>
              <input 
                type="password" 
                placeholder="PASSWORD"
                value={loginForm.password}
                onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}

              />
            </div>
            <button className="btn" type="submit" style={{ width: "100%", marginTop: 16 }} disabled={loading}>
              {loading ? "BYPASSING..." : "INITIATE OMNIPOTENT ACCESS"} <LogOut size={18} />
            </button>
          </form>
          <div style={{ textAlign: "center", marginTop: 32 }}>
             <p style={{ fontSize: "0.80rem", fontWeight: 600, color: "var(--text-secondary)" }}>HINT: ENTER 'ghost' FOR FULL SCHEMA VIEWER (NO PW REQUIRED)</p>
          </div>
        </div>
      </div>
    );
  }

  // Define schema views to match the ER diagram color groupings precisely
  const schemaModules = [
    { id: "dashboard", label: "Global Overview", icon: Activity },
    { id: "entities_blue", label: "Core: Patients & Doctors", icon: Users },
    { id: "entities_green", label: "Booking: Appts & Consults", icon: Calendar },
    { id: "entities_yellow", label: "Pharmacy: Meds & RX", icon: Pill },
    { id: "entities_orange", label: "Housing: Wards & Rooms", icon: Layout },
    { id: "entities_red", label: "Finance: Bills & Payments", icon: CreditCard }
  ];

  return (
    <div className="app-container">
      {/* Sidebar Navigation */}
      <aside className="sidebar" style={{ width: "320px" }}>
        <div className="brand" style={{ fontSize: "1.5rem" }}>
          <GitMerge size={28} color="var(--text-primary)" strokeWidth={3} />
          SCHEMA VIEWER
        </div>

        <nav className="nav-links">
          {schemaModules.map(mod => (
            <button 
              key={mod.id}
              className={`nav-item ${activeTab === mod.id ? "active" : ""}`}
              onClick={() => setActiveTab(mod.id)}
            >
              <mod.icon size={20} /> {mod.label}
            </button>
          ))}
        </nav>

        <div style={{ marginTop: "auto", borderTop: "2px solid var(--border-color)", paddingTop: 24 }}>
          <button className="btn btn-outline" onClick={logout} style={{ width: "100%" }}>
            <LogOut size={18} /> TERMINATE GHOST
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="main-content">
        <header className="header">
          <div>
            <h1>{schemaModules.find(m => m.id === activeTab)?.label?.toUpperCase()}</h1>
            <p>ACTIVE SESSION: {user.username.toUpperCase()}</p>
          </div>
          <div className="user-profile">
             <div className="user-info">
                <strong>{user.username}</strong>
                <p className="role-badge" style={{ color: "var(--text-primary)" }}>{user.role}</p>
             </div>
             <div className="avatar">
               G
             </div>
          </div>
        </header>

        {activeTab === "dashboard" && (
          <div className="solid-card">
            <h2 className="form-header"><Database size={24} strokeWidth={3}/> FULL DB ARCHITECTURE</h2>
            <p style={{ marginTop: 12, lineHeight: 1.6, fontWeight: 500 }}>
              Welcome, Ghost. You have bypassed the standard authentication portal.<br/><br/>
              This interface has been reconfigured to mirror the structural constraints and table relationships of the `hospital_schema.sql` ER diagram:
            </p>
            <ul style={{ marginTop: 24, paddingLeft: 24, lineHeight: 1.8, fontWeight: 600 }}>
              <li><strong>Blue Cluster:</strong> Patient, Doctor, Department, DoctorAvailability</li>
              <li><strong>Green Cluster:</strong> Consultation, Appointment</li>
              <li><strong>Yellow Cluster:</strong> Medicine, Prescription</li>
              <li><strong>Orange Cluster:</strong> Ward, Room, Admission</li>
              <li><strong>Red Cluster:</strong> Bill, Payment</li>
            </ul>
          </div>
        )}

        {activeTab === "entities_blue" && (
           <div className="grid-cards">
             <div className="solid-card">
               <h3 className="form-header">Patient Table</h3>
               <p><strong>Primary Key:</strong> patient_id</p>
               <p><strong>Attributes:</strong> name, age, gender (ENUM)</p>
               <hr style={{ margin: "16px 0", border: "1px solid #000" }}/>
               <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                 {patients.map(p => <div key={p.patient_id} className="list-item" style={{ padding: 8 }}>{p.name} | {p.gender} | {p.age}y</div>)}
               </div>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Doctor & Dept</h3>
               <p><strong>Doctors:</strong> doctor_id (PK), name, phone_no, dept_id (FK)</p>
               <p><strong>Departments:</strong> dept_id (PK), name</p>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Doctor Availability</h3>
               <p><strong>Attributes:</strong> availability_id (PK), doctor_id (FK), datetime, is_booked</p>
               <p><strong>Constraints:</strong> UNIQUE (doctor_id, datetime)</p>
             </div>
           </div>
        )}

        {activeTab === "entities_green" && (
           <div className="grid-cards">
             <div className="solid-card">
               <h3 className="form-header">Consultation Table</h3>
               <p><strong>Primary Key:</strong> consult_id</p>
               <p><strong>Foreign Keys:</strong> patient_id, doctor_id</p>
               <p><strong>Timestamp:</strong> consult_date</p>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Appointment Table</h3>
               <p><strong>Primary Key:</strong> appointment_id</p>
               <p><strong>Foreign Keys:</strong> consult_id, patient_id, doctor_id</p>
               <p><strong>Constraints:</strong> UNIQUE(doctor, time), UNIQUE(patient, time)</p>
             </div>
           </div>
        )}

        {activeTab === "entities_yellow" && (
           <div className="grid-cards">
             <div className="solid-card">
               <h3 className="form-header">Medicine Table</h3>
               <p><strong>Primary Key:</strong> medicine_id</p>
               <p><strong>Attributes:</strong> name (UNIQUE)</p>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Prescription Table</h3>
               <p><strong>Primary Key:</strong> prescription_id</p>
               <p><strong>Foreign Keys:</strong> consult_id, doctor_id, medicine_id</p>
               <p><strong>Attributes:</strong> dosage</p>
             </div>
           </div>
        )}

        {activeTab === "entities_orange" && (
           <div className="grid-cards">
             <div className="solid-card">
               <h3 className="form-header">Ward & Room</h3>
               <p><strong>Ward:</strong> ward_id (PK), name</p>
               <p><strong>Room:</strong> room_no (PK), ward_id (FK)</p>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Admission Table</h3>
               <p><strong>Primary Key:</strong> admission_id</p>
               <p><strong>1-1 Constraints:</strong> patient_id (UQ), room_no (UQ)</p>
               <p><strong>Tracking:</strong> admit_date, discharge_date</p>
               <p style={{ marginTop: 12, fontSize: "0.85rem", color: "var(--text-secondary)" }}>Only tracks 1-1 constraints while active (discharge_date IS NULL)</p>
             </div>
           </div>
        )}

        {activeTab === "entities_red" && (
           <div className="grid-cards">
             <div className="solid-card">
               <h3 className="form-header">Bill Table</h3>
               <p><strong>Primary Key:</strong> bill_id</p>
               <p><strong>Connections:</strong> patient, doctor, consult, admission</p>
               <p><strong>Accounting:</strong> total_amount, status (Pending/Paid)</p>
             </div>
             <div className="solid-card">
               <h3 className="form-header">Payment Table</h3>
               <p><strong>Primary Key:</strong> payment_id</p>
               <p><strong>Foreign Key:</strong> bill_id</p>
               <p><strong>Validation:</strong> amount (CHECK &gt; 0), method, date</p>
             </div>
           </div>
        )}

      </main>
    </div>
  );
}

export default App;
